head.b:template-skin:

/* =============================================
   hakki.in — Custom Blogger Template
   Author: Sandeep Hakki
   Site: https://hakki.in
============================================= */

/* === Reset === */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { overflow-x: hidden; scroll-behavior: smooth; }
a { text-decoration: none; color: inherit; }
img { max-width: 100%; vertical-align: middle; border: 0; }
ul, ol { list-style: none; }
.quickedit, .home-link, .Attribution, .feed-links,
.post-footer-line, .item-control, h2.date-header, h4.date-header,
#navbar-iframe, .navbar, .status-msg-wrap { display: none !important; }

/* === Variables === */
:root {
  --primary: #0062FF;
  --primary-dark: #0047CC;
  --accent: #00C2A8;
  --bg: #F7F8FC;
  --surface: #FFFFFF;
  --border: #E8ECF4;
  --text: #1A1F36;
  --text-secondary: #6B7494;
  --font: 'Inter', -apple-system, BlinkMacSystemFont, sans-serif;
  --mono: 'JetBrains Mono', monospace;
  --radius: 12px;
  --shadow: 0 2px 16px rgba(0,98,255,0.07);
  --shadow-hover: 0 8px 32px rgba(0,98,255,0.14);
  --max-width: 1100px;
  --transition: all 0.25s ease;
}

/* === Base === */
body {
  font-family: var(--font);
  font-size: 15px;
  color: var(--text);
  background: var(--bg);
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
}

/* === Preloader === */
#hk-preloader {
  position: fixed; inset: 0; z-index: 9999;
  background: var(--text);
  display: flex; align-items: center; justify-content: center;
  transition: opacity 0.5s ease;
}
.hk-loader-ring {
  width: 40px; height: 40px;
  border: 3px solid rgba(255,255,255,0.15);
  border-top-color: var(--primary);
  border-radius: 50%;
  animation: hk-spin 0.8s linear infinite;
}
@keyframes hk-spin { to { transform: rotate(360deg); } }

/* === Layout === */
#hk-outer { max-width: 100%; }
.hk-container { max-width: var(--max-width); margin: 0 auto; padding: 0 24px; }

/* === Top Bar === */
#hk-topbar {
  background: var(--text);
  color: rgba(255,255,255,0.55);
  font-size: 12px;
  padding: 8px 0;
}
.hk-topbar-inner {
  display: flex; align-items: center; justify-content: space-between;
}
.hk-topbar-email a { color: rgba(255,255,255,0.55); }
.hk-topbar-email a:hover { color: #fff; }

/* === Nav === */
#hk-nav {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
  position: sticky; top: 0; z-index: 100;
  box-shadow: var(--shadow);
}
.hk-nav-inner {
  display: flex; align-items: center; justify-content: space-between;
  height: 64px;
}
.hk-logo {
  display: flex; align-items: center; gap: 10px;
  font-size: 20px; font-weight: 700; color: var(--text);
  letter-spacing: -0.5px;
}
.hk-logo-dot { color: var(--primary); }
.hk-logo img { height: 36px; width: auto; }
.hk-nav-links { display: flex; gap: 4px; }
.hk-nav-links a {
  padding: 8px 14px; border-radius: 8px;
  font-size: 14px; font-weight: 500; color: var(--text-secondary);
  transition: var(--transition);
}
.hk-nav-links a:hover { background: var(--bg); color: var(--primary); }
.hk-nav-cta {
  background: var(--primary); color: #fff !important;
  padding: 8px 18px; border-radius: 8px;
  font-size: 14px; font-weight: 600;
  transition: var(--transition);
}
.hk-nav-cta:hover { background: var(--primary-dark) !important; color: #fff !important; }

/* Mobile Nav Toggle */
.hk-nav-toggle {
  display: none; background: none; border: none;
  cursor: pointer; padding: 8px;
  flex-direction: column; gap: 5px;
}
.hk-nav-toggle span {
  display: block; width: 22px; height: 2px;
  background: var(--text); border-radius: 2px;
  transition: var(--transition);
}

/* === Hero Section === */
#hk-hero {
  background: linear-gradient(135deg, #0A0F1E 0%, #0D2040 50%, #0A1628 100%);
  padding: 80px 0 60px;
  position: relative; overflow: hidden;
}
#hk-hero::before {
  content: '';
  position: absolute; top: -200px; right: -200px;
  width: 500px; height: 500px;
  background: radial-gradient(circle, rgba(0,98,255,0.15) 0%, transparent 70%);
  pointer-events: none;
}
#hk-hero::after {
  content: '';
  position: absolute; bottom: -100px; left: -100px;
  width: 350px; height: 350px;
  background: radial-gradient(circle, rgba(0,194,168,0.1) 0%, transparent 70%);
  pointer-events: none;
}
.hk-hero-inner {
  display: flex; align-items: center; gap: 60px;
  position: relative; z-index: 1;
}
.hk-hero-photo {
  flex-shrink: 0; position: relative;
}
.hk-hero-photo img {
  width: 220px; height: 220px; border-radius: 50%;
  object-fit: cover; object-position: top;
  border: 4px solid rgba(0,98,255,0.4);
  box-shadow: 0 0 0 8px rgba(0,98,255,0.1);
}
.hk-hero-badge {
  position: absolute; bottom: 10px; right: -5px;
  background: var(--accent); color: #fff;
  font-size: 11px; font-weight: 600; letter-spacing: 0.5px;
  padding: 4px 10px; border-radius: 20px;
  box-shadow: 0 2px 8px rgba(0,194,168,0.4);
}
.hk-hero-content { flex: 1; }
.hk-hero-greeting {
  font-size: 13px; font-weight: 600; letter-spacing: 2px;
  text-transform: uppercase; color: var(--accent);
  margin-bottom: 10px; display: block;
}
.hk-hero-name {
  font-size: 48px; font-weight: 700; color: #fff;
  letter-spacing: -1.5px; line-height: 1.1; margin-bottom: 8px;
}
.hk-hero-title {
  font-size: 18px; font-weight: 400; color: rgba(255,255,255,0.6);
  margin-bottom: 24px; line-height: 1.4;
}
.hk-hero-title strong { color: rgba(255,255,255,0.9); font-weight: 600; }
.hk-hero-tags {
  display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 28px;
}
.hk-tag {
  background: rgba(0,98,255,0.15); color: rgba(255,255,255,0.75);
  border: 1px solid rgba(0,98,255,0.3);
  padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 500;
}
.hk-hero-actions { display: flex; gap: 12px; flex-wrap: wrap; }
.hk-btn {
  display: inline-flex; align-items: center; gap: 8px;
  padding: 11px 24px; border-radius: 10px;
  font-size: 14px; font-weight: 600;
  transition: var(--transition); cursor: pointer;
}
.hk-btn-primary { background: var(--primary); color: #fff; }
.hk-btn-primary:hover { background: var(--primary-dark); transform: translateY(-1px); box-shadow: 0 6px 20px rgba(0,98,255,0.35); }
.hk-btn-outline {
  background: transparent; color: rgba(255,255,255,0.8);
  border: 1px solid rgba(255,255,255,0.2);
}
.hk-btn-outline:hover { background: rgba(255,255,255,0.08); color: #fff; }

/* === Stats Bar === */
#hk-stats {
  background: var(--surface);
  border-bottom: 1px solid var(--border);
}
.hk-stats-inner {
  display: grid; grid-template-columns: repeat(4, 1fr);
  divide: var(--border);
}
.hk-stat-item {
  padding: 20px 24px; text-align: center;
  border-right: 1px solid var(--border);
}
.hk-stat-item:last-child { border-right: none; }
.hk-stat-number { font-size: 28px; font-weight: 700; color: var(--primary); line-height: 1; }
.hk-stat-label { font-size: 12px; color: var(--text-secondary); margin-top: 4px; font-weight: 500; }

/* === Section Titles === */
.hk-section { padding: 64px 0; }
.hk-section-alt { background: var(--surface); }
.hk-section-title {
  font-size: 13px; font-weight: 700; letter-spacing: 2px;
  text-transform: uppercase; color: var(--primary);
  margin-bottom: 8px;
}
.hk-section-heading {
  font-size: 30px; font-weight: 700; color: var(--text);
  letter-spacing: -0.5px; margin-bottom: 40px; line-height: 1.2;
}
.hk-section-heading span { color: var(--primary); }

/* === About === */
.hk-about-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 48px; align-items: start; }
.hk-about-text p { color: var(--text-secondary); line-height: 1.8; margin-bottom: 16px; }
.hk-about-text p:last-child { margin-bottom: 0; }
.hk-info-list { display: flex; flex-direction: column; gap: 12px; }
.hk-info-item {
  display: grid; grid-template-columns: 140px 1fr; gap: 12px;
  padding: 14px 0; border-bottom: 1px solid var(--border); align-items: start;
}
.hk-info-item:last-child { border-bottom: none; }
.hk-info-key { font-size: 12px; font-weight: 600; color: var(--text-secondary); text-transform: uppercase; letter-spacing: 1px; padding-top: 2px; }
.hk-info-val { font-size: 14px; color: var(--text); line-height: 1.5; }
.hk-info-val a { color: var(--primary); }
.hk-info-val a:hover { text-decoration: underline; }

/* === Skills === */
.hk-skills-grid { display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; }
.hk-skill-card {
  background: var(--bg); border: 1px solid var(--border);
  border-radius: var(--radius); padding: 20px;
}
.hk-skill-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 10px; }
.hk-skill-name { font-size: 14px; font-weight: 600; color: var(--text); }
.hk-skill-pct { font-size: 13px; font-weight: 700; color: var(--primary); }
.hk-skill-bar { height: 6px; background: var(--border); border-radius: 3px; overflow: hidden; }
.hk-skill-fill { height: 100%; background: linear-gradient(90deg, var(--primary), var(--accent)); border-radius: 3px; transition: width 1s ease; }

/* Certs */
.hk-certs { display: flex; flex-wrap: wrap; gap: 10px; margin-top: 32px; }
.hk-cert-badge {
  display: flex; align-items: center; gap: 8px;
  background: var(--surface); border: 1px solid var(--border);
  border-radius: 8px; padding: 8px 14px; font-size: 13px; font-weight: 500;
  color: var(--text);
}
.hk-cert-badge::before {
  content: '✦'; color: var(--primary); font-size: 10px;
}

/* === Timeline === */
.hk-timeline { position: relative; }
.hk-timeline::before {
  content: ''; position: absolute; left: 50%; top: 0; bottom: 0;
  width: 2px; background: var(--border); transform: translateX(-50%);
}
.hk-timeline-group { margin-bottom: 48px; }
.hk-timeline-era {
  text-align: center; position: relative; margin-bottom: 32px;
}
.hk-timeline-era-label {
  display: inline-block; background: var(--primary); color: #fff;
  padding: 6px 20px; border-radius: 20px; font-size: 13px; font-weight: 600;
  position: relative; z-index: 1;
}
.hk-timeline-items { display: flex; flex-direction: column; gap: 24px; }
.hk-tl-item {
  display: grid; grid-template-columns: 1fr 40px 1fr; gap: 0; align-items: start;
}
.hk-tl-item.left .hk-tl-content { grid-column: 1; padding-right: 36px; }
.hk-tl-item.left .hk-tl-dot { grid-column: 2; }
.hk-tl-item.left .hk-tl-empty { grid-column: 3; }
.hk-tl-item.right .hk-tl-empty { grid-column: 1; }
.hk-tl-item.right .hk-tl-dot { grid-column: 2; }
.hk-tl-item.right .hk-tl-content { grid-column: 3; padding-left: 36px; }
.hk-tl-dot {
  display: flex; align-items: flex-start; justify-content: center;
  padding-top: 16px;
}
.hk-tl-dot-inner {
  width: 12px; height: 12px; border-radius: 50%;
  background: var(--primary); border: 3px solid var(--surface);
  box-shadow: 0 0 0 2px var(--primary);
  flex-shrink: 0;
}
.hk-tl-card {
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); padding: 20px 24px;
  box-shadow: var(--shadow);
  transition: var(--transition);
}
.hk-tl-card:hover { box-shadow: var(--shadow-hover); transform: translateY(-2px); }
.hk-tl-date {
  font-size: 11px; font-weight: 700; letter-spacing: 1.5px;
  text-transform: uppercase; color: var(--primary); margin-bottom: 6px;
}
.hk-tl-card h3 {
  font-size: 16px; font-weight: 700; color: var(--text); margin-bottom: 4px; line-height: 1.3;
}
.hk-tl-card h3 a { color: var(--primary); }
.hk-tl-card h3 a:hover { text-decoration: underline; }
.hk-tl-card p { font-size: 13px; color: var(--text-secondary); line-height: 1.7; margin-top: 8px; }
.hk-tl-card ul { margin-top: 8px; padding-left: 0; }
.hk-tl-card ul li {
  font-size: 13px; color: var(--text-secondary); line-height: 1.6;
  padding: 2px 0 2px 16px; position: relative;
}
.hk-tl-card ul li::before {
  content: '→'; position: absolute; left: 0; color: var(--primary); font-size: 11px;
}
.hk-tl-img {
  display: block; width: 100%; margin-top: 12px;
  border-radius: 8px; object-fit: cover;
  max-height: 200px;
}

/* === Blog Grid === */
#hk-blog { padding: 64px 0; }
.hk-blog-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }
.post-grid-item { /* used by Blogger */ }
.hk-post-card {
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); overflow: hidden;
  transition: var(--transition); height: 100%;
}
.hk-post-card:hover { box-shadow: var(--shadow-hover); transform: translateY(-3px); }
.hk-post-thumb {
  width: 100%; height: 180px; object-fit: cover; display: block;
  background: linear-gradient(135deg, #e8ecf4, #d0d7e8);
}
.hk-post-body { padding: 20px; }
.hk-post-labels { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 10px; }
.hk-post-label {
  font-size: 11px; font-weight: 600; letter-spacing: 0.5px;
  text-transform: uppercase; color: var(--primary);
  background: rgba(0,98,255,0.08); padding: 3px 8px; border-radius: 4px;
}
.hk-post-title {
  font-size: 16px; font-weight: 700; color: var(--text);
  line-height: 1.4; margin-bottom: 8px;
}
.hk-post-title a { color: inherit; }
.hk-post-title a:hover { color: var(--primary); }
.hk-post-snippet { font-size: 13px; color: var(--text-secondary); line-height: 1.7; margin-bottom: 14px; }
.hk-post-meta { font-size: 12px; color: var(--text-secondary); display: flex; align-items: center; gap: 8px; }
.hk-post-read-more {
  display: inline-flex; align-items: center; gap: 4px;
  font-size: 13px; font-weight: 600; color: var(--primary);
  margin-top: 12px; transition: var(--transition);
}
.hk-post-read-more:hover { gap: 8px; }

/* Single post / article page */
.item #hk-content-layout { display: grid; grid-template-columns: 1fr 300px; gap: 32px; align-items: start; }
.post-body, .post-outer {
  background: var(--surface); border-radius: var(--radius);
  padding: 32px; margin-bottom: 24px; border: 1px solid var(--border);
}
.post-title { font-size: 28px; font-weight: 700; color: var(--text); margin-bottom: 12px; line-height: 1.3; }
.post-title a { color: inherit; }
.post-header-line { font-size: 13px; color: var(--text-secondary); margin-bottom: 20px; }
.post-body p { margin-bottom: 16px; line-height: 1.8; color: var(--text-secondary); }
.post-body h2, .post-body h3, .post-body h4 { color: var(--text); font-weight: 700; margin: 24px 0 10px; }
.post-body code { font-family: var(--mono); background: var(--bg); padding: 2px 6px; border-radius: 4px; font-size: 13px; }
.post-body pre { background: #0A0F1E; color: #e8ecf4; padding: 20px; border-radius: 10px; overflow-x: auto; margin: 20px 0; }
.post-body pre code { background: none; padding: 0; color: inherit; }
.post-body img { border-radius: 8px; margin: 16px 0; }
.post-body blockquote {
  border-left: 3px solid var(--primary); padding: 12px 20px;
  background: rgba(0,98,255,0.04); border-radius: 0 8px 8px 0;
  margin: 20px 0; font-style: italic; color: var(--text-secondary);
}
.post-body a { color: var(--primary); text-decoration: underline; }

/* Sidebar */
#hk-sidebar .hk-widget {
  background: var(--surface); border: 1px solid var(--border);
  border-radius: var(--radius); padding: 20px; margin-bottom: 20px;
}
#hk-sidebar .hk-widget-title {
  font-size: 11px; font-weight: 700; letter-spacing: 2px;
  text-transform: uppercase; color: var(--text-secondary);
  margin-bottom: 14px; padding-bottom: 10px; border-bottom: 1px solid var(--border);
}
/* Popular Posts */
.PopularPosts .item-thumbnail { width: 60px; height: 60px; float: left; margin-right: 12px; border-radius: 8px; overflow: hidden; }
.PopularPosts .item-thumbnail img { width: 60px; height: 60px; object-fit: cover; }
.PopularPosts .item-title { font-size: 13px; font-weight: 600; line-height: 1.4; }
.PopularPosts .item-title a { color: var(--text); }
.PopularPosts .item-title a:hover { color: var(--primary); }
.PopularPosts .widget-content ul li { overflow: hidden; padding: 10px 0; border-bottom: 1px solid var(--border); }
.PopularPosts .widget-content ul li:last-child { border-bottom: none; padding-bottom: 0; }
/* Labels */
.cloud-label-widget-content { display: flex; flex-wrap: wrap; gap: 6px; }
.cloud-label-widget-content .label-size a {
  background: var(--bg); color: var(--text-secondary);
  padding: 4px 10px; border-radius: 6px; font-size: 12px; font-weight: 500;
  border: 1px solid var(--border); display: block;
  transition: var(--transition);
}
.cloud-label-widget-content .label-size a:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.label-count { display: none; }
/* Blog Archive */
.BlogArchive ul li { padding: 6px 0; border-bottom: 1px solid var(--border); }
.BlogArchive ul li:last-child { border-bottom: none; }
.BlogArchive ul li a { font-size: 13px; color: var(--text-secondary); }
.BlogArchive ul li a:hover { color: var(--primary); }

/* Pagination */
#blog-pager { text-align: center; padding: 32px 0; }
#blog-pager a {
  display: inline-block; padding: 10px 24px; border-radius: 8px;
  border: 1px solid var(--border); font-size: 14px; font-weight: 600;
  color: var(--text); margin: 0 4px; transition: var(--transition);
}
#blog-pager a:hover { background: var(--primary); color: #fff; border-color: var(--primary); }

/* Related Posts */
.related { display: flex; gap: 16px; list-style: none; margin: 24px 0; flex-wrap: wrap; }
.related li { width: calc(33% - 12px); }
.related-thumb { height: 120px; border-radius: 8px; overflow: hidden; margin-bottom: 8px; }
.related-img { display: block; width: 100%; height: 100%; background-size: cover !important; border-radius: 8px; }
.related-title a { font-size: 13px; font-weight: 600; color: var(--text); line-height: 1.4; }
.related-title a:hover { color: var(--primary); }

/* Comments */
.comment-form iframe { width: 100% !important; border: none; border-radius: var(--radius); }
.comments-section { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 24px; margin-top: 24px; }
.comments h4 { font-size: 18px; font-weight: 700; color: var(--text); margin-bottom: 20px; }
.comment-block { padding: 16px 0; border-bottom: 1px solid var(--border); }
.comment-block:last-child { border-bottom: none; }
.comment-author { font-weight: 600; font-size: 14px; color: var(--text); }
.comment-content { font-size: 13px; color: var(--text-secondary); margin-top: 4px; line-height: 1.6; }
.comment-header { font-size: 12px; color: var(--text-secondary); margin-bottom: 4px; }

/* Share */
.share-art { display: flex; gap: 10px; flex-wrap: wrap; margin: 20px 0; }
.share-art a {
  display: inline-flex; align-items: center; gap: 6px;
  padding: 8px 14px; border-radius: 8px; font-size: 13px; font-weight: 500;
  border: 1px solid var(--border); color: var(--text);
  transition: var(--transition);
}
.share-art a:hover { background: var(--primary); color: #fff; border-color: var(--primary); }
.goog-inline-block.share-button { display: inline-block; }

/* === Footer === */
#hk-footer {
  background: var(--text);
  color: rgba(255,255,255,0.55);
  padding: 48px 0 0;
}
.hk-footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr; gap: 40px; margin-bottom: 40px; }
.hk-footer-brand .hk-logo { color: #fff; margin-bottom: 12px; }
.hk-footer-tagline { font-size: 13px; line-height: 1.7; margin-bottom: 16px; }
.hk-footer-social { display: flex; gap: 10px; }
.hk-footer-social a {
  width: 36px; height: 36px; border-radius: 8px;
  background: rgba(255,255,255,0.07); border: 1px solid rgba(255,255,255,0.1);
  display: flex; align-items: center; justify-content: center;
  font-size: 14px; color: rgba(255,255,255,0.6);
  transition: var(--transition);
}
.hk-footer-social a:hover { background: var(--primary); border-color: var(--primary); color: #fff; }
.hk-footer-col h4 {
  font-size: 12px; font-weight: 700; letter-spacing: 2px;
  text-transform: uppercase; color: rgba(255,255,255,0.9);
  margin-bottom: 16px;
}
.hk-footer-col ul { display: flex; flex-direction: column; gap: 8px; }
.hk-footer-col ul a { font-size: 13px; color: rgba(255,255,255,0.5); transition: var(--transition); }
.hk-footer-col ul a:hover { color: #fff; }
.hk-footer-bottom {
  border-top: 1px solid rgba(255,255,255,0.07);
  padding: 20px 0; text-align: center; font-size: 12px;
}
.hk-footer-bottom a { color: rgba(255,255,255,0.5); }
.hk-footer-bottom a:hover { color: #fff; }

/* === 404 === */
.post-404 { text-align: center; padding: 80px 24px; }
.title-404 { font-size: 120px; font-weight: 700; color: var(--border); line-height: 1; }
.ops-404 { font-size: 20px; color: var(--text-secondary); margin: 16px 0 32px; }
.link-404 a { background: var(--primary); color: #fff; padding: 12px 28px; border-radius: 10px; font-weight: 600; }

/* === Scroll-to-top === */
#hk-scrolltop {
  position: fixed; bottom: 32px; right: 32px; z-index: 500;
  width: 44px; height: 44px; border-radius: 10px;
  background: var(--primary); color: #fff;
  display: flex; align-items: center; justify-content: center;
  font-size: 18px; cursor: pointer; opacity: 0; pointer-events: none;
  transition: var(--transition); box-shadow: 0 4px 16px rgba(0,98,255,0.3);
  border: none;
}
#hk-scrolltop.visible { opacity: 1; pointer-events: all; }
#hk-scrolltop:hover { background: var(--primary-dark); transform: translateY(-2px); }

/* === Responsive === */
@media (max-width: 1024px) {
  .hk-hero-name { font-size: 38px; }
  .hk-blog-grid { grid-template-columns: repeat(2, 1fr); }
  .hk-timeline::before { display: none; }
  .hk-tl-item { grid-template-columns: 1fr; }
  .hk-tl-item.left .hk-tl-content,
  .hk-tl-item.right .hk-tl-content { grid-column: 1; padding: 0; }
  .hk-tl-item.left .hk-tl-dot,
  .hk-tl-item.right .hk-tl-dot,
  .hk-tl-item.left .hk-tl-empty,
  .hk-tl-item.right .hk-tl-empty { display: none; }
  .hk-about-grid { grid-template-columns: 1fr; gap: 32px; }
  .item #hk-content-layout { grid-template-columns: 1fr; }
  .hk-footer-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 768px) {
  .hk-hero-inner { flex-direction: column; text-align: center; gap: 32px; }
  .hk-hero-tags { justify-content: center; }
  .hk-hero-actions { justify-content: center; }
  .hk-hero-name { font-size: 32px; }
  .hk-stats-inner { grid-template-columns: repeat(2, 1fr); }
  .hk-stat-item { border-right: none; border-bottom: 1px solid var(--border); }
  .hk-blog-grid { grid-template-columns: 1fr; }
  .hk-skills-grid { grid-template-columns: 1fr; }
  .hk-nav-links { display: none; }
  .hk-nav-links.open { display: flex; flex-direction: column; position: absolute; top: 64px; left: 0; right: 0; background: var(--surface); border-bottom: 1px solid var(--border); padding: 8px 16px 16px; z-index: 99; }
  .hk-nav-toggle { display: flex; }
  .hk-footer-grid { grid-template-columns: 1fr; }
  .hk-container { padding: 0 16px; }
  .hk-section { padding: 48px 0; }
  .hk-hero-photo img { width: 160px; height: 160px; }
  .related li { width: 100%; }
}

head.script:
//
var no_image = "https://blogger.googleusercontent.com/img/b/R29vZ2xl/AVvXsEg6W-gyZgTmpNVxJArUEtF235wyLB03N9n55rz23W9gOHAlwnRuFSOEqTLNDlEZ4Oo6KIS1sHsBGgmLnLLbEIdNG1P-EYUqk9kXoESmdPXqkjpJ1ZK1W7RZ-mE9bDtUFd6abxWRID2fYWo/s1600-r/nth.png";
var month_format = [, "Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
var more_text = "Read More";
var comments_text = "Post a Comment";
var pagenav_prev = "← Newer";
var pagenav_next = "Older →";
//

body.script:
//

// Preloader
window.addEventListener('load', function() {
  var pre = document.getElementById('hk-preloader');
  if (pre) { pre.style.opacity = '0'; setTimeout(function(){ pre.style.display = 'none'; }, 500); }
});

// Scroll to top button
window.addEventListener('scroll', function() {
  var btn = document.getElementById('hk-scrolltop');
  if (btn) { btn.classList.toggle('visible', window.scrollY > 400); }
});

// Sticky nav shadow on scroll
window.addEventListener('scroll', function() {
  var nav = document.getElementById('hk-nav');
  if (nav) { nav.style.boxShadow = window.scrollY > 10 ? '0 4px 24px rgba(0,0,0,0.10)' : ''; }
});

// Related Posts (by label, no external dependency)
$(document).ready(function() {
  $('#related-posts').each(function() {
    var el = $(this), label = el.text().split(',')[0].trim(), count = 3;
    if (!label) return;
    $.ajax({
      url: '/feeds/posts/default/-/' + encodeURIComponent(label) + '?alt=json-in-script&max-results=' + count,
      type: 'get', dataType: 'jsonp',
      success: function(data) {
        if (!data.feed || !data.feed.entry) return;
        var html = '<h4 style="font-size:18px;font-weight:700;color:var(--text);margin:32px 0 16px;">Related Posts</h4><ul class="related">';
        $.each(data.feed.entry, function(i, entry) {
          var url = '', img = no_image, title = entry.title.$t;
          $.each(entry.link, function(j, link) { if (link.rel === 'alternate') url = link.href; });
          if (entry.media$thumbnail) img = entry.media$thumbnail.url.replace('/s72-c/', '/s400-c/');
          html += '<li><div class="related-thumb"><a class="related-img" href="' + url + '" style="background:url(' + img + ') center/cover no-repeat;display:block;width:100%;height:100%;"></a></div><h3 class="related-title"><a href="' + url + '">' + title + '</a></h3></li>';
        });
        html += '</ul>';
        el.html(html);
      }
    });
  });
});

